import numpy as np
import math

def kanerva_coding_td(prototypes: np.ndarray, threshold: float, episodes: list,
                      gamma: float, alpha: float, query_states: np.ndarray) -> tuple:
    k = prototypes.shape[0]
    weights = [0.0] * k

    def get_features(state):
        feats = []
        for proto in prototypes:
            dist = math.sqrt(sum((s - p) ** 2 for s, p in zip(state, proto)))
            feats.append(1.0 if dist <= threshold else 0.0)
        return feats

    def estimate_value(feats):
        return sum(w * f for w, f in zip(weights, feats))

    for episode in episodes:
        for state, reward, next_state, done in episode:
            phi = get_features(state)
            v = estimate_value(phi)

            if done:
                td_error = reward - v
            else:
                phi_next = get_features(next_state)
                v_next = estimate_value(phi_next)
                td_error = reward + gamma * v_next - v

            for i in range(k):
                weights[i] += alpha * td_error * phi[i]

    values = []
    for state in query_states:
        phi = get_features(state)
        values.append(estimate_value(phi))

    return ([round(w, 4) for w in weights], [round(v, 4) for v in values])
